前言：本篇文章属于Java后端代码实现，并没有前端代码 准备工作实现微信小程序API V3支付功能先要获取到MCH_ID（商户ID）、MP_APP_ID（小程序APPID）、API_V3KEY（APPV3 密钥）、PRIVATE_KEY（商户证书密钥），具体获取方式请看微信小程序支付接入前准备 添加微信支付依赖 123456789101112131415161718192021&lt;dependency&gt; &lt;groupId&gt;com.github.binarywang&lt;/groupId&gt; &lt;artifactId&gt;weixin-java-pay&lt;/artifactId&gt; &lt;version&gt;4.1.0&lt;/version&gt; &lt;/dependency&gt; &lt;dependency&gt; &lt;groupId&gt;com.github.binarywang&lt;/groupId&gt; &lt;artifactId&gt;weixin-java-mp&lt;/artifactId&gt; &lt;version&gt;4.1.0&lt;/version&gt; &lt;/dependency&gt; &lt;!--微信支付依赖 v3版本--&gt; &lt;dependency&gt; &lt;groupId&gt;com.github.wechatpay-apiv3&lt;/groupId&gt; &lt;artifactId&gt;wechatpay-apache-httpclient&lt;/artifactId&gt; &lt;version&gt;0.2.2&lt;/version&gt; &lt;/dependency&gt; &lt;dependency&gt; &lt;groupId&gt;org.apache.httpcomponents&lt;/groupId&gt; &lt;artifactId&gt;httpclient&lt;/artifactId&gt; &lt;/dependency&gt;&lt;/dependencies&gt; 编写微信小程序配置类 注意：文档演示商户证书私钥等数据采用保存在配置类中，可自行使用其他方式保存，提倡使用properties配置文件方式，后期可直接替换文件无需更改代码 12345678910111213141516171819202122232425262728293031323334353637383940414243444546@Data@Configurationpublic class WeChatMiniProperties { /** * 商户号 */ public static final String MCH_ID = &quot;xxxxxxxxxxxxxxxxxx&quot;; /** * 商户证书私钥 */ public static final String PRIVATE_KEY = &quot;-----BEGIN PRIVATE KEY-----
&quot; + &quot;-----END PRIVATE KEY-----
&quot;; /** * 商户证书序列号 */ public static final String MCH_SERIAL_NO = &quot;xxxxxxxxxxxxxxxxxx&quot;; /** * API_V3密钥 */ public static final String API_V3KEY = &quot;xxxxxxxxxxxxxxxxxx&quot;; /** * 小程序appId */ public static final String MP_APP_ID = &quot;xxxxxxxxxxxxxxxxxx&quot;; public static final String MP_APP_SECRET = &quot;xxxxxxxxxxxxxxxxxx&quot;; /** * jsapi下单url */ public static final String V3_JSAPI_URL = &quot;https://api.mch.weixin.qq.com/v3/pay/transactions/jsapi&quot;; /** * 小程序支付异步通知地址 */ public static final String MINI_NOTIFY_URL = &quot;https://xxxx/xxx/xxx/mini/notify/order&quot;;} 编写微信小程序支付工具类 @Slf4j@Componentpublic class WechatMiniUtil { public CloseableHttpClient getHttpClient() { CloseableHttpClient httpClient = null; // 加载商户私钥（privateKey：私钥字符串） try { PrivateKey merchantPrivateKey = PemUtil.loadPrivateKey( new ByteArrayInputStream(WeChatMiniProperties.PRIVATE_KEY.getBytes(&quot;utf-8&quot;))); //使用自动更新的签名验证器，不需要传入证书 AutoUpdateCertificatesVerifier verifier = new AutoUpdateCertificatesVerifier( new WechatPay2Credentials(WeChatMiniProperties.MCH_ID, new PrivateKeySigner(WeChatMiniProperties.MCH_SERIAL_NO, merchantPrivateKey)), WeChatMiniProperties.API_V3KEY.getBytes(&quot;utf-8&quot;)); // 初始化httpClient httpClient = WechatPayHttpClientBuilder.create() .withMerchant(WeChatMiniProperties.MCH_ID, WeChatMiniProperties.MCH_SERIAL_NO, merchantPrivateKey) .withValidator(new WechatPay2Validator(verifier)) .build(); } catch (UnsupportedEncodingException e) { e.printStackTrace(); } return httpClient; } String getSign(String appid, String prepay_id, String nonceStr, long timestamp) { //构造签名串 List&lt;String&gt; strings = new LinkedList&lt;&gt;(); strings.add(appid + &quot;
&quot;); strings.add(timestamp + &quot;
&quot;); strings.add(nonceStr + &quot;
&quot;); strings.add(prepay_id + &quot;
&quot;); StringBuilder builder = new StringBuilder(); for (String string : strings) { builder.append(string); } //计算签名值 PrivateKey rsa = PemUtil.loadPrivateKey( new ByteArrayInputStream(WeChatMiniProperties.PRIVATE_KEY.getBytes(StandardCharsets.UTF_8))); Sign sign = SecureUtil.sign(SignAlgorithm.SHA256withRSA); sign.setPrivateKey(rsa); byte[] signData = sign.sign(builder.toString().getBytes(StandardCharsets.UTF_8)); return Base64.getEncoder().encodeToString(signData); } /** * @Description: 验证签名 * @Param: [serial, message, signature]请求头中带的序列号, 验签名串, 请求头中的应答签名 * @return: boolean */ public boolean signVerify(String serial, String message, String signature) { AutoUpdateCertificatesVerifier verifier = null; try { // 加载商户私钥（privateKey：私钥字符串） PrivateKey merchantPrivateKey = PemUtil.loadPrivateKey( new ByteArrayInputStream(WeChatMiniProperties.PRIVATE_KEY.getBytes(&quot;utf-8&quot;))); //使用自动更新的签名验证器，不需要传入证书 verifier = new AutoUpdateCertificatesVerifier( new WechatPay2Credentials(WeChatMiniProperties.MCH_ID, new PrivateKeySigner(WeChatMiniProperties.MCH_SERIAL_NO, merchantPrivateKey)), WeChatMiniProperties.API_V3KEY.getBytes(&quot;utf-8&quot;)); return verifier.verify(serial, message.getBytes(&quot;utf-8&quot;), signature); } catch (UnsupportedEncodingException e) { e.printStackTrace(); } return false; } /** * @Description: 解密订单信息 * @Param: [body] 应答报文主体 * @return: java.lang.String */ public String decryptOrder(String body) { try { AesUtil aesUtil = new AesUtil(WeChatMiniProperties.API_V3KEY.getBytes(&quot;utf-8&quot;)); ObjectMapper objectMapper = new ObjectMapper(); JsonNode node = objectMapper.readTree(body); JsonNode resource = node.get(&quot;resource&quot;); String ciphertext = resource.get(&quot;ciphertext&quot;).textValue(); String associatedData = resource.get(&quot;associated_data&quot;).textValue(); String nonce = resource.get(&quot;nonce&quot;).textValue(); return aesUtil.decryptToString(associatedData.getBytes(&quot;utf-8&quot;), nonce.getBytes(&quot;utf-8&quot;), ciphertext); } catch (UnsupportedEncodingException e) { e.printStackTrace(); } catch (IOException e) { e.printStackTrace(); } catch (GeneralSecurityException e) { e.printStackTrace(); } return &quot;&quot;; } /** ** 获取IP地址 */ public String getClientIpAddress() { HttpServletRequest request = getRequest(); // 获取请求主机IP地址,如果通过联盟商进来，则透过防火墙获取真实IP地址 String headerName = &quot;x-forwarded-for&quot;; String ip = request.getHeader(headerName); if (null != ip &amp;&amp; ip.length() != 0 &amp;&amp; !&quot;unknown&quot;.equalsIgnoreCase(ip)) { // 多次反向联盟商后会有多个IP值，第一个IP才是真实IP,它们按照英文逗号','分割 if (ip.indexOf(&quot;,&quot;) != -1) { ip = ip.split(&quot;,&quot;)[0]; } } if (checkIp(ip)) { headerName = &quot;Proxy-Client-IP&quot;; ip = request.getHeader(headerName); } if (checkIp(ip)) { headerName = &quot;WL-Proxy-Client-IP&quot;; ip = request.getHeader(headerName); } if (checkIp(ip)) { headerName = &quot;HTTP_CLIENT_IP&quot;; ip = request.getHeader(headerName); } if (checkIp(ip)) { headerName = &quot;HTTP_X_FORWARDED_FOR&quot;; ip = request.getHeader(headerName); } if (checkIp(ip)) { headerName = &quot;X-Real-IP&quot;; ip = request.getHeader(headerName); } if (checkIp(ip)) { headerName = &quot;remote addr&quot;; ip = request.getRemoteAddr(); // 127.0.0.1 ipv4, 0:0:0:0:0:0:0:1 ipv6 if (&quot;127.0.0.1&quot;.equals(ip) || &quot;0:0:0:0:0:0:0:1&quot;.equals(ip)) { //根据网卡取本机配置的IP InetAddress inet = null; try { inet = InetAddress.getLocalHost(); } catch (UnknownHostException e) { return &quot;127.0.0.0&quot;; } ip = inet.getHostAddress(); } } log.info(&quot;getClientIp IP is &quot; + ip + &quot;, headerName = &quot; + headerName); return ip; } public WxPayMpOrderResult createMiniOrder(WxPayUnifiedOrderRequest orderRequest) throws Exception { // 小程序下单 CloseableHttpClient httpClient = getHttpClient(); HttpPost httpPost = new HttpPost(WeChatMiniProperties.V3_JSAPI_URL); httpPost.addHeader(&quot;Accept&quot;, &quot;application/json&quot;); httpPost.addHeader(&quot;Content-type&quot;, &quot;application/json; charset=utf-8&quot;); Map&lt;String, Object&gt; orderParam = new HashMap(); orderParam.put(&quot;mchid&quot;, WeChatMiniProperties.MCH_ID); orderParam.put(&quot;out_trade_no&quot;, orderRequest.getOutTradeNo()); orderParam.put(&quot;appid&quot;, WeChatMiniProperties.MP_APP_ID); orderParam.put(&quot;description&quot;, orderRequest.getBody()); orderParam.put(&quot;notify_url&quot;, WeChatMiniProperties.MINI_NOTIFY_URL); orderParam.put(&quot;amount&quot;, Map.ofEntries( entry(&quot;total&quot;, orderRequest.getTotalFee()), entry(&quot;currency&quot;, &quot;CNY&quot;) )); orderParam.put(&quot;payer&quot;, Map.ofEntries( entry(&quot;openid&quot;, orderRequest.getOpenid()) )); log.info(&quot;微信小程序下单请求参数：{}&quot;, JSONUtil.parseObj(orderParam)); httpPost.setEntity(new StringEntity(JSONUtil.parseObj(orderParam).toString(), &quot;UTF-8&quot;)); //完成签名并执行请求 CloseableHttpResponse response = httpClient.execute(httpPost); try { int statusCode = response.getStatusLine().getStatusCode(); WxPayAppOrderResult orderResult = new WxPayAppOrderResult(); if (statusCode == 200) { //处理成功返回的数据 String body = EntityUtils.toString(response.getEntity()); com.alibaba.fastjson.JSONObject jsonObject = JSON.parseObject(body); //获取预支付交易会话标识 prepay_id String prepayId = jsonObject.getString(&quot;prepay_id&quot;); Long timestamp = System.currentTimeMillis() / 1000L; WxPayMpOrderResult payResult = WxPayMpOrderResult.builder().appId(WeChatMiniProperties.MP_APP_ID).timeStamp(String.valueOf(timestamp)) .nonceStr(orderRequest.getNonceStr()).packageValue(&quot;prepay_id=&quot; + prepayId).signType(&quot;RSA&quot;).build(); payResult.setPaySign(getSign(WeChatMiniProperties.MP_APP_ID, &quot;prepay_id=&quot; + prepayId, orderRequest.getNonceStr(), timestamp)); log.info(&quot;微信小程序下单返回参数：{}&quot;,payResult); return payResult; } else { log.error(&quot;failed,resp code = &quot; + statusCode + &quot;,return body = &quot; + EntityUtils.toString(response.getEntity())); throw new IOException(&quot;request failed&quot;); } } finally { response.close(); } }} 支付请求模型 123456789101112131415161718@Data@ApiModel(description = &quot;支付请求模型&quot;)public class WxUnifiedOrderParam implements Serializable { @ApiModelProperty(&quot;订单号id&quot;) private List&lt;Long&gt; ids; @ApiModelProperty(value = &quot;订单编号不能为空&quot;) private String orderNo; @ApiModelProperty(value = &quot;交易类型&quot;, example = &quot;APP|JSAPI(小程序也用JSAPI)&quot;) @NotNull(message = &quot;交易类型不能为空&quot;) private String tradeType; @ApiModelProperty(value = &quot;支付金额&quot;, example = &quot;1&quot;) @NotNull(message = &quot;支付金额不能为空&quot;) private String payPrice; } 控制层实现下单接口以及支付回调通知 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172@ApiOperation(value = &quot;小程序统一下单接口&quot;)@PostMapping(&quot;/mini/createOrder&quot;)@AccessLimit(seconds = 3, maxCount = 1)public ObjectRestResponse&lt;Object&gt; createMiniOrder(@RequestBody @Validated WxUnifiedOrderParam unifiedOrderParam) throws Exception { log.info(&quot;小程序统一下单接口：{}&quot;, JSON.toJSON(unifiedOrderParam)); //较验订单,根据自己业务进行校验，演示案例不进行校验 //获取订单，请根据自己需求修改代码 List&lt;Order&gt; orderList = orderService.listByIds(unifiedOrderParam.getIds()); WxPayUnifiedOrderRequest orderRequest = new WxPayUnifiedOrderRequest(); orderRequest.setBody(&quot;XXX商品购买&quot;); BigDecimal totalAmount = orderList.stream().map(Order::getOrderPrice).reduce(BigDecimal.ZERO, BigDecimal::add); orderRequest.setTotalFee(BaseWxPayRequest.yuanToFen(String.valueOf(totalAmount))); orderRequest.setNotifyUrl(properties.getOrderMiniNotifyUrl()); orderRequest.setNonceStr(UUIDUtils.getRandom(32)); orderRequest.setOutTradeNo(Objects.nonNull(unifiedOrderParam.getOrderNo()) ? unifiedOrderParam.getOrderNo() : orderList.get(0).getBatchNo()); orderRequest.setSpbillCreateIp(wechatMiniUtil.getClientIpAddress()); //获取当前用户的小程序openid if (userAuthUtil.getUserId().isPresent()) { User user = userService.getCurrentUserInfo(); orderRequest.setOpenid(user.getMiniOpenId()); } if (Objects.isNull(orderRequest.getOpenid())) { throw new BizException(&quot;请绑定微信小程序&quot;); } return new ObjectRestResponse&lt;&gt;().rel(true).data(wechatMiniUtil.createMiniOrder(orderRequest));}@ApiOperation(value = &quot;小程序支付回调通知处理&quot;)@RequestMapping(&quot;/mini/notify/order&quot;)public Object miniOrderNotify(HttpServletRequest request) { log.info(&quot;小程序支付回调通知处理:{}&quot;, request); Map result = new HashMap(); result.put(&quot;code&quot;, &quot;FAIL&quot;); result.put(&quot;message&quot;, &quot;失败&quot;); try { StringBuilder signStr = new StringBuilder(); // 应答时间戳
 signStr.append(request.getHeaders(&quot;Wechatpay-Timestamp&quot;)).append(&quot;
&quot;); // 应答随机串
 signStr.append(request.getHeaders(&quot;Wechatpay-Nonce&quot;)).append(&quot;
&quot;); // 应答报文主体
 BufferedReader br = request.getReader(); String str = null; StringBuilder builder = new StringBuilder(); while ((str = br.readLine()) != null) { builder.append(str); } log.info(&quot;微信小程序支付应答报文主体：{}&quot;, builder); signStr.append(builder.toString()).append(&quot;
&quot;); // 第一步：验证签名 if (wechatMiniUtil.signVerify(request.getHeader(&quot;Wechatpay-Serial&quot;), signStr.toString(), request.getHeader(&quot;Wechatpay-Signature&quot;))) { result.put(&quot;message&quot;, &quot;sign error&quot;); log.error(&quot;小程序签名错误或失效！&quot;); } // 第二步：解密密文 String decryptOrder = wechatMiniUtil.decryptOrder(builder.toString()); log.info(&quot;解密后支付信息：{}&quot;, decryptOrder); JSONObject notifyResult = JSON.parseObject(decryptOrder); if (&quot;SUCCESS&quot;.equals(notifyResult.getString(&quot;trade_state&quot;))) { // 支付成功... //根据支付信息查询已存的订单信息，进行状态改变等操作，根据业务操作 result.put(&quot;code&quot;, &quot;SUCCESS&quot;); result.put(&quot;message&quot;, &quot;成功&quot;); } } } catch (IOException e) { log.error(&quot;小程序支付回调报错:{}&quot;, e); } return result;}
